15	func CreateOrgHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
16		return func(c echo.Context) error {
17			var req dto.CreateOrgRequest
18			if err := c.Bind(&req); err != nil {
19				return err
20			}
21			if err := c.Validate(req); err != nil {
22				return err
23			}
24	
25			org, err := service.CreateOrg(c.Request().Context(), db, &req)
26			if err != nil {
27				return err
28			}
29	
30			role := getRole(c)
31			setAuditNewValue(c, service.MaskOrg(org, role))
32			return c.JSON(http.StatusCreated, service.MaskOrg(org, role))
33		}
34	}
35	
36	func ListOrgsHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
37		return func(c echo.Context) error {
38			limit, _ := strconv.Atoi(c.QueryParam("limit"))
39			offset, _ := strconv.Atoi(c.QueryParam("offset"))
40			if limit <= 0 {
41				limit = 50
42			}
43			if offset < 0 {
44				offset = 0
45			}
46	
47			role := getRole(c)
48			orgID, err := getListOrgScope(c)
49			if err != nil {
50				return err
51			}
52	
53			orgs, err := service.ListOrgs(c.Request().Context(), db, orgID, limit, offset)
54			if err != nil {
55				return err
56			}
57	
58			result := make([]dto.OrgResponse, len(orgs))
59			for i := range orgs {
60				result[i] = service.MaskOrg(&orgs[i], role)
61			}
62	
63			return c.JSON(http.StatusOK, result)
64		}
65	}
66	
67	func GetOrgHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
68		return func(c echo.Context) error {
69			id, err := uuid.Parse(c.Param("id"))
70			if err != nil {
71				return echo.NewHTTPError(http.StatusBadRequest, "invalid org id")
72			}
73	
74			org, err := service.GetOrg(c.Request().Context(), db, id)
75			if err != nil {
76				return err
77			}
78	
79			if err := enforceOrgOwnership(c, db,org.ID); err != nil {
80				return err
81			}
82	
83			role := getRole(c)
84			return c.JSON(http.StatusOK, service.MaskOrg(org, role))
85		}
86	}
87	
88	func UpdateOrgHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
89		return func(c echo.Context) error {
90			id, err := uuid.Parse(c.Param("id"))
91			if err != nil {
92				return echo.NewHTTPError(http.StatusBadRequest, "invalid org id")
93			}
94	
95			var req dto.UpdateOrgRequest
96			if err := c.Bind(&req); err != nil {
97				return err
98			}
99			if err := c.Validate(req); err != nil {
100				return err
101			}
102	
103			old, err := service.GetOrg(c.Request().Context(), db, id)
104			if err != nil {
105				return err
106			}
107			role := getRole(c)
108			setAuditOldValue(c, service.MaskOrg(old, role))
109	
110			org, err := service.UpdateOrg(c.Request().Context(), db, id, &req)
111			if err != nil {
112				return err
113			}
114	
115			masked := service.MaskOrg(org, role)
116			setAuditNewValue(c, masked)
117			return c.JSON(http.StatusOK, masked)
118		}
119	}
120	
121	func DeleteOrgHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
122		return func(c echo.Context) error {
123			id, err := uuid.Parse(c.Param("id"))
124			if err != nil {
125				return echo.NewHTTPError(http.StatusBadRequest, "invalid org id")
126			}
127	
128			existing, err := service.GetOrg(c.Request().Context(), db, id)
129			if err != nil {
130				return err
131			}
132			role := getRole(c)
133			setAuditOldValue(c, service.MaskOrg(existing, role))
134	
135			if err := service.DeleteOrg(c.Request().Context(), db, id); err != nil {
136				return err
137			}
138	
139			return c.NoContent(http.StatusNoContent)
140		}
141	}
