49		}
50	
51		if req.Name != nil {
52			org.Name = *req.Name
53		}
54		if req.TaxID != nil {
55			org.TaxID = req.TaxID
56		}
57		if req.Address != nil {
58			org.Address = req.Address
59		}
60		if req.Timezone != nil {
61			org.Timezone = *req.Timezone
62		}
63	
64		org.UpdatedAt = time.Now().UTC()
