15	func CreateNotificationTemplate(ctx context.Context, db sqlx.ExtContext, t *model.NotificationTemplate) error {
16		query := `INSERT INTO notification_templates (id, code, title_tmpl, body_tmpl, default_enabled, created_at)
17			VALUES (:id, :code, :title_tmpl, :body_tmpl, :default_enabled, :created_at)`
18		_, err := sqlx.NamedExecContext(ctx, db, query, t)
19		return err
20	}
21	
22	func GetNotificationTemplate(ctx context.Context, db sqlx.ExtContext, id uuid.UUID) (*model.NotificationTemplate, error) {
23		var t model.NotificationTemplate
24		err := sqlx.GetContext(ctx, db, &t, "SELECT * FROM notification_templates WHERE id = $1", id)
25		if errors.Is(err, sql.ErrNoRows) {
26			return nil, apperror.ErrNotFound
27		}
28		return &t, err
29	}
