55	func UpsertSubscription(ctx context.Context, db sqlx.ExtContext, sub *model.NotificationSubscription) error {
56		query := `INSERT INTO notification_subscriptions (id, user_id, template_id, opted_out, updated_at)
57			VALUES (:id, :user_id, :template_id, :opted_out, :updated_at)
58			ON CONFLICT (user_id, template_id) DO UPDATE SET opted_out = EXCLUDED.opted_out, updated_at = EXCLUDED.updated_at`
59		_, err := sqlx.NamedExecContext(ctx, db, query, sub)
60		return err
