78	func CreateJob(ctx context.Context, db sqlx.ExtContext, job *model.NotificationJob) error {
79		query := `INSERT INTO notification_jobs (user_id, template_id, params, status, scheduled_at, created_at)
80			VALUES ($1, $2, $3, $4, $5, $6)
81			RETURNING id`
82		return sqlx.GetContext(ctx, db, &job.ID, query,
83			job.UserID, job.TemplateID, job.Params, job.Status, job.ScheduledAt, job.CreatedAt)
