86	func ClaimPendingJobs(ctx context.Context, db sqlx.ExtContext, limit int) ([]model.NotificationJob, error) {
87		var jobs []model.NotificationJob
88		query := `UPDATE notification_jobs SET status = 'processing', processed_at = NOW()
89			WHERE id IN (
90				SELECT id FROM notification_jobs
91				WHERE status = 'pending' AND scheduled_at <= NOW()
