16	func Connect(cfg *config.Config) (*sqlx.DB, error) {
17		db, err := sqlx.Connect("postgres", cfg.DatabaseURL)
18		if err != nil {
19			return nil, fmt.Errorf("db connect: %w", err)
20		}
21		db.SetMaxOpenConns(cfg.MaxOpenConns)
22		db.SetMaxIdleConns(cfg.MaxIdleConns)
23		return db, nil
24	}
25	
26	func RunMigrations(db *sqlx.DB, migrationsDir string) error {
27		if _, err := db.Exec(`CREATE TABLE IF NOT EXISTS schema_migrations (
28			version TEXT PRIMARY KEY,
29			applied_at TIMESTAMPTZ NOT NULL DEFAULT now()
30		)`); err != nil {
31			return fmt.Errorf("create migrations table: %w", err)
32		}
33	
34		entries, err := os.ReadDir(migrationsDir)
35		if err != nil {
36			return fmt.Errorf("read migrations dir: %w", err)
37		}
38	
39		var upFiles []string
40		for _, e := range entries {
41			if !e.IsDir() && strings.HasSuffix(e.Name(), ".up.sql") {
42				upFiles = append(upFiles, e.Name())
43			}
44		}
45		sort.Strings(upFiles)
46	
47		for _, fname := range upFiles {
48			version := strings.TrimSuffix(fname, ".up.sql")
49			var count int
50			if err := db.Get(&count, "SELECT COUNT(*) FROM schema_migrations WHERE version = $1", version); err != nil {
51				return fmt.Errorf("check migration %s: %w", version, err)
52			}
53			if count > 0 {
54				continue
55			}
56	
57			sql, err := os.ReadFile(filepath.Join(migrationsDir, fname))
58			if err != nil {
59				return fmt.Errorf("read migration %s: %w", fname, err)
60			}
61	
62			tx, err := db.Begin()
63			if err != nil {
64				return fmt.Errorf("begin tx for %s: %w", version, err)
65			}
66			if _, err := tx.Exec(string(sql)); err != nil {
67				tx.Rollback()
68				return fmt.Errorf("run migration %s: %w", version, err)
69			}
70			if _, err := tx.Exec("INSERT INTO schema_migrations (version) VALUES ($1)", version); err != nil {
71				tx.Rollback()
72				return fmt.Errorf("record migration %s: %w", version, err)
73			}
74			if err := tx.Commit(); err != nil {
75				return fmt.Errorf("commit migration %s: %w", version, err)
76			}
77		}
78		return nil
79	}
