3	import (
4		"crypto/sha256"
5		"encoding/hex"
6		"strings"
7		"time"
8	
9		"github.com/chargeops/api/internal/apperror"
10		"github.com/chargeops/api/internal/repo"
11		"github.com/chargeops/api/internal/service"
12		"github.com/jmoiron/sqlx"
13		"github.com/labstack/echo/v4"
14	)
15	
16	var skipPaths = map[string]bool{
17		"/api/v1/auth/register":      true,
18		"/api/v1/auth/login":         true,
19		"/api/v1/auth/recover":       true,
20		"/api/v1/auth/recover/reset": true,
21		"/health":                    true,
22	}
23	
24	// guestPaths allow unauthenticated access with role "guest".
25	var guestPaths = map[string]bool{
26		"/api/v1/content/carousel":  true,
27		"/api/v1/content/campaigns": true,
28		"/api/v1/content/rankings":  true,
29	}
30	
31	func Auth(db *sqlx.DB) echo.MiddlewareFunc {
32		return func(next echo.HandlerFunc) echo.HandlerFunc {
33			return func(c echo.Context) error {
34				path := c.Request().URL.Path
35				if skipPaths[path] {
36					return next(c)
37				}
38	
39				authHeader := c.Request().Header.Get("Authorization")
40				if !strings.HasPrefix(authHeader, "Bearer ") {
41					// Allow guest access to content list endpoints
42					if c.Request().Method == "GET" && guestPaths[path] {
43						c.Set("role", "guest")
44						c.Set("permissions", map[string]bool{"content.read": true})
45						return next(c)
46					}
47					return apperror.ErrUnauthorized
48				}
49				token := strings.TrimPrefix(authHeader, "Bearer ")
50	
51				hash := sha256.Sum256([]byte(token))
52				tokenHash := hex.EncodeToString(hash[:])
53	
54				ctx := c.Request().Context()
55	
56				session, err := repo.GetSessionByTokenHash(ctx, db, tokenHash)
57				if err != nil {
58					return apperror.ErrUnauthorized
59				}
60	
61				now := time.Now()
62	
63				// Check idle expiry - refresh endpoint handles its own idle check in the service
64				if path != "/api/v1/auth/refresh" {
65					if now.After(session.IdleExpiresAt) {
66						return apperror.ErrSessionExpired
67					}
68				}
69	
70				// Check absolute expiry
71				if now.After(session.AbsExpiresAt) {
72					return apperror.ErrSessionExpired
73				}
74	
75				// Verify device ID
76				deviceID := c.Request().Header.Get("X-Device-Id")
77				if deviceID != session.DeviceID {
78					return apperror.ErrDeviceMismatch
79				}
80	
81				// Load user
82				user, err := repo.GetUserByID(ctx, db, session.UserID)
83				if err != nil {
84					return apperror.ErrUnauthorized
85				}
86	
87				c.Set("user_id", user.ID)
88				c.Set("role", user.Role)
89				c.Set("org_id", user.OrgID)
90				c.Set("session_id", session.ID)
91				c.Set("session", session)
92				c.Set("user", user)
93	
94				// Load effective permissions into context for RequirePermission middleware
95				perms, err := service.GetEffectivePermissions(ctx, db, user.ID, user.Role)
96				if err == nil {
97					permSet := make(map[string]bool, len(perms))
98					for _, p := range perms {
99						if p.Granted {
100							permSet[p.Name] = true
101						}
102					}
103					c.Set("permissions", permSet)
104				}
105	
106				return next(c)
107			}
108		}
109	}
