15	
16	// extractAuditEntity parses the URL path to find the primary resource type and ID.
17	// For nested/action routes like /api/v1/versions/:id/activate or /api/v1/users/:id/role,
18	// it finds the UUID and uses the segment before it as the entity type.
19	func extractAuditEntity(path string) (entityType, entityID string) {
20		parts := strings.Split(strings.Trim(path, "/"), "/")
21		// Walk backwards to find the first UUID-shaped segment (36 chars with hyphens)
22		for i := len(parts) - 1; i >= 0; i-- {
23			if len(parts[i]) == 36 && strings.Count(parts[i], "-") == 4 {
24				entityID = parts[i]
25				if i > 0 {
26					entityType = parts[i-1]
27				}
28				return
29			}
30		}
31		// No UUID found — use last segment as entity type (e.g., POST /api/v1/orgs)
32		if len(parts) > 0 {
33			entityType = parts[len(parts)-1]
34		}
35		return
36	}
37	
38	func Audit(db *sqlx.DB) echo.MiddlewareFunc {
39		return func(next echo.HandlerFunc) echo.HandlerFunc {
40			return func(c echo.Context) error {
41				err := next(c)
42	
43				method := c.Request().Method
44				if method != "POST" && method != "PUT" && method != "DELETE" {
45					return err
46				}
47	
48				status := c.Response().Status
49				if status < 200 || status >= 300 {
50					return err
51				}
52	
53				var userID *string
54				if uid, ok := c.Get("user_id").(uuid.UUID); ok {
55					s := uid.String()
56					userID = &s
57				}
58	
59				action := method + " " + c.Path()
60	
61				entityType, entityID := extractAuditEntity(c.Request().URL.Path)
62	
63				var oldValue *json.RawMessage
64				if ov, ok := c.Get("audit_old_value").(json.RawMessage); ok {
65					oldValue = &ov
66				}
67	
68				var newValue *json.RawMessage
69				if nv, ok := c.Get("audit_new_value").(json.RawMessage); ok {
70					newValue = &nv
71				}
72	
73				reqID, _ := c.Get("request_id").(string)
74				ip := c.RealIP()
75	
76				auditLog := &model.AuditLog{
77					UserID:     userID,
78					Action:     action,
79					EntityType: entityType,
80					EntityID:   entityID,
81					OldValue:   oldValue,
82					NewValue:   newValue,
83					IPAddress:  &ip,
84					RequestID:  &reqID,
85					CreatedAt:  time.Now(),
86				}
87	
88				ctx := c.Request().Context()
89				if auditErr := repo.CreateAuditLog(ctx, db, auditLog); auditErr != nil {
90					log.Error().Err(auditErr).Msg("failed to create audit log")
91				}
92	
93				return err
94			}
95		}
96	}
