16	func StartNotificationWorker(ctx context.Context, db *sqlx.DB) {
17		ticker := time.NewTicker(5 * time.Second)
18		defer ticker.Stop()
19		for {
20			select {
21			case <-ctx.Done():
22				return
23			case <-ticker.C:
24				processBatch(ctx, db)
25			}
26		}
27	}
28	
29	func processBatch(ctx context.Context, db *sqlx.DB) {
30		jobs, err := repo.ClaimPendingJobs(ctx, db, 50)
31		if err != nil {
32			log.Error().Err(err).Msg("failed to claim notification jobs")
33			return
34		}
35		for _, job := range jobs {
36			func(j model.NotificationJob) {
37				jobCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
38				defer cancel()
39				processJob(jobCtx, db, j)
40			}(job)
41		}
42	}
43	
44	func processJob(ctx context.Context, db *sqlx.DB, job model.NotificationJob) {
45		defer func() {
46			if r := recover(); r != nil {
47				log.Error().Int64("job_id", job.ID).Interface("panic", r).Msg("panic in processJob")
48				repo.UpdateJobStatus(ctx, db, job.ID, "failed", "panic")
49			}
50		}()
51	
52		// 1. Check opt-out
53		optedOut, err := repo.IsOptedOut(ctx, db, job.UserID, job.TemplateID)
54		if err != nil {
55			log.Error().Err(err).Int64("job_id", job.ID).Msg("failed to check opt-out")
56			repo.UpdateJobStatus(ctx, db, job.ID, "failed", "opt_out_check_error")
57			return
58		}
59		if optedOut {
60			if err := repo.UpdateJobStatus(ctx, db, job.ID, "suppressed", "opted_out"); err != nil {
61				log.Error().Err(err).Int64("job_id", job.ID).Msg("failed to update suppressed status")
62			}
63			return
64		}
65	
66		// 2. Check quiet hours (9 PM - 7 AM local time)
67		userTZ := getUserTimezone(ctx, db, job.UserID)
68		loc, err := time.LoadLocation(userTZ)
69		if err != nil {
70			loc = time.UTC
71		}
72		localNow := time.Now().In(loc)
73		if IsQuietHours(localNow.Hour()) {
74			next7AM := ComputeNext7AM(localNow, loc)
75			repo.RescheduleJob(ctx, db, job.ID, next7AM)
76			return
77		}
78	
79		// 3. Check rate limit: max 2 per user per template per day (user-local day)
80		// Use time.Date to get midnight in the user's local timezone (Truncate uses UTC)
81		y, m, d := localNow.Date()
82		localDay := time.Date(y, m, d, 0, 0, 0, 0, loc)
83		nextDay := localDay.AddDate(0, 0, 1)
84		count, err := repo.CountDeliveredInWindow(ctx, db, job.UserID, job.TemplateID, localDay.UTC(), nextDay.UTC())
85		if err != nil {
86			log.Error().Err(err).Int64("job_id", job.ID).Msg("failed to count delivered today")
87			repo.UpdateJobStatus(ctx, db, job.ID, "failed", "rate_limit_check_error")
88			return
89		}
90		if count >= 2 {
91			repo.UpdateJobStatus(ctx, db, job.ID, "suppressed", "rate_limit")
92			return
93		}
94	
95		// 4. Render and deliver to inbox
96		tmpl, err := repo.GetNotificationTemplate(ctx, db, job.TemplateID)
97		if err != nil {
98			log.Error().Err(err).Int64("job_id", job.ID).Msg("failed to get template")
99			repo.UpdateJobStatus(ctx, db, job.ID, "failed", "template_not_found")
100			return
101		}
102	
103		title := RenderTemplate(tmpl.TitleTmpl, job.Params)
104		body := RenderTemplate(tmpl.BodyTmpl, job.Params)
105	
106		msg := &model.Message{
107			ID:         uuid.New(),
108			UserID:     job.UserID,
109			TemplateID: job.TemplateID,
110			Title:      title,
111			Body:       body,
112			CreatedAt:  time.Now().UTC(),
113		}
114		if err := repo.CreateMessage(ctx, db, msg); err != nil {
115			log.Error().Err(err).Int64("job_id", job.ID).Msg("failed to create message")
116			repo.UpdateJobStatus(ctx, db, job.ID, "failed", "delivery_failed")
117			return
118		}
119	
120		repo.UpdateJobStatus(ctx, db, job.ID, "delivered", "")
121	
122		// 5. Increment delivered stat
123		repo.IncrementDeliveryStat(ctx, db, job.TemplateID, "delivered")
124	}
