126	func getUserTimezone(ctx context.Context, db sqlx.ExtContext, userID interface{}) string {
127		var tz string
128		err := sqlx.GetContext(ctx, db, &tz,
129			`SELECT COALESCE(o.timezone, 'UTC') FROM users u
130			 LEFT JOIN organizations o ON o.id = u.org_id
131			 WHERE u.id = $1`, userID)
132		if err != nil {
133			return "UTC"
134		}
135		return tz
136	}
