138	// IsQuietHours returns true if the given hour falls within quiet hours (9 PM - 7 AM).
139	func IsQuietHours(hour int) bool {
140		return hour >= 21 || hour < 7
141	}
142	
143	func ComputeNext7AM(now time.Time, loc *time.Location) time.Time {
144		next := time.Date(now.Year(), now.Month(), now.Day(), 7, 0, 0, 0, loc)
145		if now.Hour() >= 7 {
146			next = next.AddDate(0, 0, 1)
147		}
148		return next
149	}
150	
151	func RenderTemplate(tmpl string, params []byte) string {
152		if len(params) == 0 {
153			return tmpl
154		}
155		result := tmpl
156		// Simple key-value replacement from JSON params
157		var m map[string]string
158		if err := json.Unmarshal(params, &m); err != nil {
159			return tmpl
160		}
161		for k, v := range m {
162			result = strings.ReplaceAll(result, "{{"+k+"}}", v)
163		}
164		return result
165	}
