15		"github.com/labstack/echo/v4"
16	)
17	
18	func maskWarehouseAddress(w *model.Warehouse, role string) {
19		if w.Address != nil {
20			masked := masking.MaskAddress(*w.Address, role)
21			w.Address = &masked
22		}
23	}
24	
25	func CreateWarehouseHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
26		return func(c echo.Context) error {
27			var req dto.CreateWarehouseRequest
28			if err := c.Bind(&req); err != nil {
29				return err
30			}
31			if err := c.Validate(req); err != nil {
32				return err
33			}
34	
35			role := getRole(c)
36			if role != "administrator" {
37				callerOrgID := getOrgID(c)
38				if callerOrgID == nil {
39					return apperror.ErrForbidden
40				}
41				req.OrgID = *callerOrgID
42			}
43	
44			w, err := service.CreateWarehouse(c.Request().Context(), db, &req)
45			if err != nil {
46				return err
47			}
48	
49			maskWarehouseAddress(w, role)
50			setAuditNewValue(c, w)
51			return c.JSON(http.StatusCreated, w)
52		}
53	}
54	
55	func ListWarehousesHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
56		return func(c echo.Context) error {
57			limit, _ := strconv.Atoi(c.QueryParam("limit"))
58			offset, _ := strconv.Atoi(c.QueryParam("offset"))
59			if limit <= 0 {
60				limit = 50
61			}
62			if offset < 0 {
63				offset = 0
64			}
65	
66			orgID, err := getListOrgScope(c)
67			if err != nil {
68				return err
69			}
70	
71			warehouses, err := service.ListWarehouses(c.Request().Context(), db, orgID, limit, offset)
72			if err != nil {
73				return err
74			}
75	
76			role := getRole(c)
77			for i := range warehouses {
78				maskWarehouseAddress(&warehouses[i], role)
79			}
80	
81			return c.JSON(http.StatusOK, warehouses)
82		}
83	}
84	
85	func GetWarehouseHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
86		return func(c echo.Context) error {
87			id, err := uuid.Parse(c.Param("id"))
88			if err != nil {
89				return echo.NewHTTPError(http.StatusBadRequest, "invalid warehouse id")
90			}
91	
92			w, err := service.GetWarehouse(c.Request().Context(), db, id)
93			if err != nil {
94				return err
95			}
96	
97			if err := enforceOrgOwnership(c, db,w.OrgID); err != nil {
98				return err
99			}
100	
101			role := getRole(c)
102			maskWarehouseAddress(w, role)
103			return c.JSON(http.StatusOK, w)
104		}
105	}
106	
107	func UpdateWarehouseHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
108		return func(c echo.Context) error {
109			id, err := uuid.Parse(c.Param("id"))
110			if err != nil {
111				return echo.NewHTTPError(http.StatusBadRequest, "invalid warehouse id")
112			}
113	
114			existing, err := service.GetWarehouse(c.Request().Context(), db, id)
115			if err != nil {
116				return err
117			}
118			if err := enforceOrgOwnership(c, db,existing.OrgID); err != nil {
119				return err
120			}
121			role := getRole(c)
122			maskedOld := *existing
123			maskWarehouseAddress(&maskedOld, role)
124			setAuditOldValue(c, &maskedOld)
125	
126			var req dto.UpdateWarehouseRequest
127			if err := c.Bind(&req); err != nil {
128				return err
129			}
130			if err := c.Validate(req); err != nil {
131				return err
132			}
133	
134			w, err := service.UpdateWarehouse(c.Request().Context(), db, id, &req)
135			if err != nil {
136				return err
137			}
138	
139			maskWarehouseAddress(w, role)
140			setAuditNewValue(c, w)
141			return c.JSON(http.StatusOK, w)
142		}
143	}
144	
145	func DeleteWarehouseHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
146		return func(c echo.Context) error {
147			id, err := uuid.Parse(c.Param("id"))
148			if err != nil {
149				return echo.NewHTTPError(http.StatusBadRequest, "invalid warehouse id")
150			}
151	
152			existing, err := service.GetWarehouse(c.Request().Context(), db, id)
153			if err != nil {
154				return err
155			}
156			if err := enforceOrgOwnership(c, db,existing.OrgID); err != nil {
157				return err
158			}
159			maskedOld := *existing
160			maskWarehouseAddress(&maskedOld, getRole(c))
161			setAuditOldValue(c, &maskedOld)
162	
163			if err := service.DeleteWarehouse(c.Request().Context(), db, id); err != nil {
164				return err
165			}
166	
167			return c.NoContent(http.StatusNoContent)
168		}
169	}
170	
171	func CreateZoneHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
172		return func(c echo.Context) error {
173			warehouseID, err := uuid.Parse(c.Param("id"))
174			if err != nil {
175				return echo.NewHTTPError(http.StatusBadRequest, "invalid warehouse id")
176			}
177	
178			w, err := service.GetWarehouse(c.Request().Context(), db, warehouseID)
179			if err != nil {
180				return err
181			}
182			if err := enforceOrgOwnership(c, db,w.OrgID); err != nil {
183				return err
184			}
185	
186			var req dto.CreateZoneRequest
187			if err := c.Bind(&req); err != nil {
188				return err
189			}
190			if err := c.Validate(req); err != nil {
191				return err
192			}
