15	// enforceVersionOrgOwnership resolves a version to its template and checks org ownership.
16	func enforceVersionOrgOwnership(c echo.Context, db *sqlx.DB, versionID uuid.UUID) error {
17		version, err := service.GetVersion(c.Request().Context(), db, versionID)
18		if err != nil {
19			return err
20		}
21		tmpl, err := service.GetPriceTemplate(c.Request().Context(), db, version.TemplateID)
22		if err != nil {
23			return err
24		}
25		return enforceOrgOwnership(c, db, tmpl.OrgID)
26	}
