28	func CreateTemplateHandler(db *sqlx.DB, cfg *config.Config) echo.HandlerFunc {
29		return func(c echo.Context) error {
30			var req dto.CreatePriceTemplateRequest
31			if err := c.Bind(&req); err != nil {
32				return err
33			}
34			if err := c.Validate(req); err != nil {
35				return err
36			}
37	
38			// Derive org from the referenced station or device.
39			ctx := c.Request().Context()
40			var ownerOrgID uuid.UUID
41			switch {
42			case req.StationID != nil:
43				station, err := service.GetStation(ctx, db, *req.StationID)
44				if err != nil {
45					return err
46				}
47				ownerOrgID = station.OrgID
48			case req.DeviceID != nil:
49				device, err := service.GetDevice(ctx, db, *req.DeviceID)
50				if err != nil {
51					return err
52				}
53				station, err := service.GetStation(ctx, db, device.StationID)
54				if err != nil {
55					return err
56				}
57				ownerOrgID = station.OrgID
58			default:
59				return echo.NewHTTPError(400, "station_id or device_id is required")
60			}
61	
62			// Merchants can only create templates for their own org's stations/devices.
63			if err := enforceOrgOwnership(c, db, ownerOrgID); err != nil {
64				return err
65			}
66	
67			tmpl, err := service.CreatePriceTemplate(c.Request().Context(), db, ownerOrgID, &req)
68			if err != nil {
69				return err
70			}
71	
72			setAuditNewValue(c, tmpl)
73			return c.JSON(http.StatusCreated, tmpl)
74		}
75	}
