439				"params":      map[string]string{"n": fmt.Sprintf("%d", i)},
440			}, adminToken)
441			if resp.StatusCode != http.StatusCreated {
442				data := parseJSON(t, resp)
443				t.Fatalf("send #%d: %d %v", i, resp.StatusCode, data)
444			}
445		}
446	
447		// Wait for all jobs to finish processing
448		deadline := time.Now().Add(90 * time.Second)
449		for time.Now().Before(deadline) {
450			var pendingCount int
451			err := db.QueryRow(
452				`SELECT COUNT(*) FROM notification_jobs
453				 WHERE user_id = $1 AND template_id = $2 AND status IN ('pending','processing')`,
454				userID, templateID).Scan(&pendingCount)
455			if err != nil {
456				time.Sleep(500 * time.Millisecond)
457				continue
458			}
459			if pendingCount == 0 {
460				break
461			}
462			time.Sleep(500 * time.Millisecond)
463		}
464	
465		// Count delivered and suppressed jobs
466		var deliveredCount, suppressedCount int
467		var suppressReason sql.NullString
468		err := db.QueryRow(
469			`SELECT COUNT(*) FROM notification_jobs
470			 WHERE user_id = $1 AND template_id = $2 AND status = 'delivered'`,
471			userID, templateID).Scan(&deliveredCount)
472		if err != nil {
473			t.Fatal(err)
474		}
475		err = db.QueryRow(
476			`SELECT COUNT(*) FROM notification_jobs
477			 WHERE user_id = $1 AND template_id = $2 AND status = 'suppressed'`,
478			userID, templateID).Scan(&suppressedCount)
479		if err != nil {
480			t.Fatal(err)
481		}
482	
483		if deliveredCount != 2 {
484			t.Fatalf("expected 2 delivered, got %d", deliveredCount)
485		}
486		if suppressedCount != 1 {
487			t.Fatalf("expected 1 suppressed, got %d", suppressedCount)
488		}
489	
490		// Verify the suppressed job has reason "rate_limit"
491		err = db.QueryRow(
492			`SELECT suppress_reason FROM notification_jobs
493			 WHERE user_id = $1 AND template_id = $2 AND status = 'suppressed'
494			 ORDER BY id DESC LIMIT 1`,
495			userID, templateID).Scan(&suppressReason)
496		if err != nil {
497			t.Fatal(err)
498		}
499		if !suppressReason.Valid || suppressReason.String != "rate_limit" {
500			t.Fatalf("expected suppress_reason 'rate_limit', got %q", suppressReason.String)
501		}
502	
503		// Verify only 2 messages appear in user's inbox
504		resp = doRequest(t, "GET", "/api/v1/notifications/inbox", nil, userToken)
505		inbox := parseJSONArray(t, resp)
506		count := 0
507		for _, m := range inbox {
508			msg := m.(map[string]interface{})
509			if msg["template_id"] == templateID {
510				count++
511			}
512		}
513		if count != 2 {
514			t.Fatalf("expected 2 messages in inbox, got %d", count)
515		}
516	}
